export type WarCountry = 'germany' | 'japan' | 'usa' | 'uk' | 'france' | 'ussr' | 'italy' | 'other';
export type WarSide = 'axis' | 'allied' | 'neutral';
export type WarEventType = 'battle' | 'invasion' | 'bombing' | 'naval' | 'turning_point' | 'atrocity' | 'surrender' | 'treaty' | 'offensive';

export interface WarEvent {
  id: string;
  title: string;
  year: number;
  month: number; // 1–12
  latitude: number;
  longitude: number;
  countries: WarCountry[];
  side: WarSide; // axis = red, allied = blue, neutral = grey
  type: WarEventType;
  description: string; // 2-3 sentences, informative
  casualties?: string;
  significance: 1 | 2 | 3; // 1=minor, 2=major, 3=critical/turning point
  translations?: {
    ro?: { title: string; description: string };
    fr?: { title: string; description: string };
    de?: { title: string; description: string };
    es?: { title: string; description: string };
  };
}

export const WW2_YEAR_MIN = 1939;
export const WW2_YEAR_MAX = 1945;

